(function () {
    try {
        var content = execution.getVariables();
        var approverEmail = content.get('currentApproverEmail');

        logger.error('aaronPOC-v7: actors looking up: ' + approverEmail);

        var result = [];
        var queryResult = openidm.query('managed/alpha_user', {
            '_queryFilter': '/mail eq "' + approverEmail + '"'
        });
        if (queryResult && queryResult.result && queryResult.result.length > 0) {
            var user = queryResult.result[0];
            result.push({
                'id': 'managed/user/' + user._id,
                'permissions': {
                    'approve': true,
                    'reject': true,
                    'reassign': true,
                    'modify': false,
                    'comment': true
                }
            });
            logger.error('aaronPOC-v7: found approver: ' + user._id);
        }
        return result;
    } catch (e) {
        logger.error('aaronPOC-v7: actors FAILED: ' + e);
        return [];
    }
})()

